#include <vector>
#include <algorithm>
#include <numeric>

namespace stats {
    double mean(const std::vector<double>& v) {
        if (v.empty()) {
            return 0.0;
        }
        return std::accumulate(v.begin(), v.end(), 0.0) / v.size();
    }

    double median(std::vector<double> v) {
        if (v.empty()) {
            return 0.0;
        }
        std::sort(v.begin(), v.end());
        size_t size = v.size();
        if (size % 2 == 0) {
            return (v[size / 2 - 1] + v[size / 2]) / 2.0;
        } else {
            return v[size / 2];
        }
    }
}
